const matches = $input.all();
const results = [];
for (const match of matches) {
  const data = match.json;
  results.push({
    json: {
      category: data.category || 'men',
      round: parseInt(data.round) || 1,
      round_name: data.round_name || 'Finals',
      index: parseInt(data.index) || 0,
      court: data.court || 'Unknown',
      competition_source: data.competition_source || 'FIP',
      month: new Date(data.played_at || Date.now()).getMonth() + 1,
      match_id: String(data.match_id || data.id || 'N/A'),
      match_name: data.name || 'Unknown Match',
      played_at: data.played_at || 'Unknown'
    }
  });
}
return results;

const items = $input.all();
const results = [];
for (const item of items) {
  const d = item.json;
  const confidence = Math.max(d.probability_team1 || 0, d.probability_team2 || 0);
  const alert = confidence < 60 ? '⚠️ LOW CONFIDENCE' : '✅ HIGH CONFIDENCE';
  results.push({
    json: {
      match_id: d.match_id || 'N/A',
      match_name: d.match_name || 'Unknown',
      predicted_winner: d.winner || d.predicted_winner,
      probability_team1: d.probability_team1,
      probability_team2: d.probability_team2,
      confidence_level: confidence.toFixed(1) + '%',
      confidence_alert: alert,
      model: 'XGBoost Classifier (74.2% accuracy)',
      prediction_timestamp: new Date().toISOString(),
      status: d.status
    }
  });
}
return results;

const items = $input.all();
const predictions = items.map(item => ({
  match_id: item.json.match_id || 'N/A',
  predicted_winner: item.json.predicted_winner || 'Unknown',
  probability_team1: item.json.probability_team1 || 0,
  probability_team2: item.json.probability_team2 || 0,
  timestamp: item.json.prediction_timestamp || new Date().toISOString()
}));
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:5000/save_predictions',
  headers: { 'Content-Type': 'application/json' },
  body: { predictions },
  json: true
});
return [{ json: { ...response, total_saved: predictions.length } }];

const items = $input.all();
const errorData = {
  pipeline: 'Classification — Match Winner',
  timestamp: new Date().toISOString(),
  error: items[0]?.json?.error || 'Unknown error',
  match_id: items[0]?.json?.match_id || 'N/A'
};
await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:5000/log_error',
  headers: { 'Content-Type': 'application/json' },
  body: errorData,
  json: true
});
return [{ json: errorData }];

const items = $input.all();
const summary = items.map(i => i.json);
const lowConf = summary.filter(s => parseFloat(s.confidence_level) < 60);
const report = {
  timestamp: new Date().toISOString(),
  total_predictions: summary.length,
  low_confidence_matches: lowConf.length,
  summary: summary.map(s => `${s.match_name}: ${s.predicted_winner} (${s.confidence_level})`).join('\n')
};
return [{ json: report }];
